using System.Linq;
using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — c.Discriminator is correct because we configured
        // HasDiscriminator<string>("Discriminator") to preserve the EF Core 8 property name.
        // Without that config, EF Core 9 would write "$type" and this query would break.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Sync I/O (ToList) throws in EF Core 9 Cosmos — must use async
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

